class BankAccount {
  #balance;  // private — can't be accessed from outside!

  constructor(initial) {
    this.#balance = initial;
  }

  deposit(amount)  { this.#balance += amount; }
  withdraw(amount) { this.#balance -= amount; }
  get balance()    { return this.#balance; }
}

const account = new BankAccount(100);
account.deposit(50);
console.log(account.balance);  // 150 — through getter

try {
  console.log(account.#balance); // SyntaxError — truly private!
} catch(e) {
  console.log("Private field access blocked!");
}

class QueryBuilder {
  constructor(table) {
    this.table = table;
    this.columns = [];
    this.conditions = [];
    this._limit = null;
  }

  // TODO: add chainable select(col), where(cond), limit(n)

  build() {
    const cols = this.columns.length ? this.columns.join(", ") : "*";
    let q = `SELECT ${cols} FROM ${this.table}`;
    if (this.conditions.length) q += ` WHERE ${this.conditions.join(" AND ")}`;
    if (this._limit) q += ` LIMIT ${this._limit}`;
    return q;
  }
}

const query = new QueryBuilder("users")
  .select("name")
  .select("email")
  .where("age > 18")
  .where("active = true")
  .limit(10)
  .build();

console.log(query);
